import React, { useContext } from "react";
import { GeneralContext } from "./GeneralContext";
import BuyActionWindow from "./BuyActionWindow";
import WatchList from "./WatchList"; // Import your Watchlist
import Summary from "./Summary"; // Import your Summary/TopBar

const Dashboard = () => {
  const { isBuyWindowOpen, selectedStockUID } = useContext(GeneralContext);

  return (
    <div className="dashboard-container">
      {/* 1. Render your Sidebar/Watchlist */}
      <WatchList />

      <div className="content">
        {/* 2. Render your main content or Routes here */}
        <Summary />
      </div>

      {/* 3. The Buy Window Logic */}
      {isBuyWindowOpen && <BuyActionWindow uid={selectedStockUID} />}
    </div>
  );
};

export default Dashboard;
